mapper.select:
SELECT count(*) FROM hm_query.fact_support_tickets_flat

    AND customer_id = #{customerId}
    AND subject LIKE CONCAT('%', #{subject}, '%')
    AND category = #{category}
    AND priority = #{priority}
    AND state_id = #{stateId}
    AND assigned_agent_id = #{assignedAgentId}
    AND created_at >= #{startDate}
    AND created_at <= #{endDate}
    AND (subject LIKE CONCAT('%', #{q}, '%') OR customer_name LIKE CONCAT('%', #{q}, '%') OR category LIKE CONCAT('%', #{q}, '%'))

SELECT
    id                 as "id",
    customer_id        as "customerId",
    customer_name      as "customerName",
    customer_email     as "customerEmail",
    subject            as "subject",
    category           as "category",
    priority           as "priority",
    state_id           as "stateId",
    flow_id            as "flowId",
    assigned_agent_id  as "assignedAgentId",
    reopen_count       as "reopenCount",
    created_at         as "createdAt"
FROM hm_query.fact_support_tickets_flat

    AND customer_id = #{customerId}
    AND subject LIKE CONCAT('%', #{subject}, '%')
    AND category = #{category}
    AND priority = #{priority}
    AND state_id = #{stateId}
    AND assigned_agent_id = #{assignedAgentId}
    AND created_at >= #{startDate}
    AND created_at <= #{endDate}
    AND (subject LIKE CONCAT('%', #{q}, '%') OR customer_name LIKE CONCAT('%', #{q}, '%') OR category LIKE CONCAT('%', #{q}, '%'))

${orderby} ${pagination}

SELECT COUNT(*)
FROM hm_query.fact_support_tickets_flat
WHERE assigned_agent_id = #{assignedAgentId}

SELECT COUNT(*)
FROM hm_query.fact_support_tickets_flat
WHERE priority = #{priority}

SELECT COUNT(*)
FROM hm_query.fact_support_tickets_flat
